async function calcFreeDrinkThreshold(tenantId, pointsPerSar = 20, fallback = 500) {
  try {
    const items = await CoffeeItemModel.find({
      $or: [{ tenantId }, { tenantId: { $exists: false } }],
      isActive: { $ne: false },
      price: { $gt: 0 }
    }).select("price").lean().exec();
    if (!items || items.length === 0) return fallback;
    const avg = items.reduce((sum, i) => sum + (Number(i.price) || 0), 0) / items.length;
    if (avg <= 0) return fallback;
    return Math.round(avg * pointsPerSar);
  } catch {
    return fallback;
  }
}
